2002:   def handleCreateTopicsRequest(request: RequestChannel.Request): Unit = {
2003:     val zkSupport = metadataSupport.requireZkOrThrow(KafkaApis.shouldAlwaysForward(request))
2004:     val controllerMutationQuota = quotas.controllerMutation.newQuotaFor(request, strictSinceVersion = 6)
2005: 
2006:     def sendResponseCallback(results: CreatableTopicResultCollection): Unit = {
2007:       val responseData = new CreateTopicsResponseData()
2008:         .setTopics(results)
2009:       val response = new CreateTopicsResponse(responseData)
2010:       trace(s"Sending create topics response $responseData for correlation id " +
2011:         s"${request.header.correlationId} to client ${request.header.clientId}.")
2012:       requestHelper.sendResponseMaybeThrottleWithControllerQuota(controllerMutationQuota, request, response)
2013:     }
2014: 
2015:     val createTopicsRequest = request.body[CreateTopicsRequest]
2016:     val results = new CreatableTopicResultCollection(createTopicsRequest.data.topics.size)
2017:     if (!zkSupport.controller.isActive) {
2018:       createTopicsRequest.data.topics.forEach { topic =>
2019:         results.add(new CreatableTopicResult().setName(topic.name)
2020:           .setErrorCode(Errors.NOT_CONTROLLER.code))
2021:       }
2022:       sendResponseCallback(results)
2023:     } else {
2024:       createTopicsRequest.data.topics.forEach { topic =>
2025:         results.add(new CreatableTopicResult().setName(topic.name))
2026:       }
2027:       val hasClusterAuthorization = authHelper.authorize(request.context, CREATE, CLUSTER, CLUSTER_NAME,
2028:         logIfDenied = false)
2029: 
2030:       val allowedTopicNames = {
2031:         val topicNames = createTopicsRequest
2032:           .data
2033:           .topics
2034:           .asScala
2035:           .map(_.name)
2036:           .toSet
2037: 
2038:           topicNames.diff(Set(Topic.CLUSTER_METADATA_TOPIC_NAME))
2039:       }
2040: 
2041:       val authorizedTopics = if (hasClusterAuthorization) {
2042:         allowedTopicNames
2043:       } else {
2044:         authHelper.filterByAuthorized(request.context, CREATE, TOPIC, allowedTopicNames)(identity)
2045:       }
2046:       val authorizedForDescribeConfigs = authHelper.filterByAuthorized(
2047:         request.context,
2048:         DESCRIBE_CONFIGS,
2049:         TOPIC,
2050:         allowedTopicNames,
2051:         logIfDenied = false
2052:       )(identity).map(name => name -> results.find(name)).toMap
2053: 
2054:       results.forEach { topic =>
2055:         if (topic.name() == Topic.CLUSTER_METADATA_TOPIC_NAME) {
2056:           topic.setErrorCode(Errors.INVALID_REQUEST.code)
2057:           topic.setErrorMessage(s"Creation of internal topic ${Topic.CLUSTER_METADATA_TOPIC_NAME} is prohibited.")
2058:         } else if (results.findAll(topic.name).size > 1) {
2059:           topic.setErrorCode(Errors.INVALID_REQUEST.code)
2060:           topic.setErrorMessage("Found multiple entries for this topic.")
2061:         } else if (!authorizedTopics.contains(topic.name)) {
2062:           topic.setErrorCode(Errors.TOPIC_AUTHORIZATION_FAILED.code)
2063:           topic.setErrorMessage("Authorization failed.")
2064:         }
2065:         if (!authorizedForDescribeConfigs.contains(topic.name) && topic.name() != Topic.CLUSTER_METADATA_TOPIC_NAME) {
2066:           topic.setTopicConfigErrorCode(Errors.TOPIC_AUTHORIZATION_FAILED.code)
2067:         }
2068:       }
2069:       val toCreate = mutable.Map[String, CreatableTopic]()
2070:       createTopicsRequest.data.topics.forEach { topic =>
2071:         if (results.find(topic.name).errorCode == Errors.NONE.code) {
2072:           toCreate += topic.name -> topic
2073:         }
2074:       }
2075:       def handleCreateTopicsResults(errors: Map[String, ApiError]): Unit = {
2076:         errors.foreach { case (topicName, error) =>
2077:           val result = results.find(topicName)
2078:           result.setErrorCode(error.error.code)
2079:             .setErrorMessage(error.message)
2080:           // Reset any configs in the response if Create failed
2081:           if (error != ApiError.NONE) {
2082:             result.setConfigs(List.empty.asJava)
2083:               .setNumPartitions(-1)
2084:               .setReplicationFactor(-1)
2085:               .setTopicConfigErrorCode(Errors.NONE.code)
2086:           }
2087:         }
2088:         sendResponseCallback(results)
2089:       }
2090:       zkSupport.adminManager.createTopics(
2091:         createTopicsRequest.data.timeoutMs,
2092:         createTopicsRequest.data.validateOnly,
2093:         toCreate,
2094:         authorizedForDescribeConfigs,
2095:         controllerMutationQuota,
2096:         handleCreateTopicsResults)
2097:     }
2098:   }
